     1→/**
     2→ * MMS Demo Data Generator
     3→ *
     4→ * Generates realistic fleet data for the MMS demo application.
     5→ * Creates 128 trains across 3 fleets with 5+ years of historical data.
     6→ *
     7→ * Key features:
     8→ * - Cold-start algorithm for trains with no PM history
     9→ * - PM hierarchy cascade (C4 satisfies C1/C2/C3)
    10→ * - Dual triggers (mileage + time-based)
    11→ * - Bow-wave scenario generator (Chaos Monkey)
    12→ *
    13→ * @see specs/009-demo-application.md
    14→ */
    15→
    16→import { v4 as uuidv4 } from 'uuid';
    17→import {
    18→  DEMO_DEPOTS,
    19→  DEMO_FLEETS,
    20→  PM_RULES_BY_FLEET,
    21→  SERVICE_DEMAND_PROFILES,
    22→  TRACK_CONFIGS,
    23→} from './data';
    24→import type {
    25→  DemoMileageReading,
    26→  DemoPMHistory,
    27→  DemoTrain,
    28→  GeneratedData,
    29→  GeneratorConfig,
    30→} from './types';
    31→
    32→/** Seeded random number generator for reproducible results */
    33→class SeededRandom {
    34→  private seed: number;
    35→
    36→  constructor(seed: number) {
    37→    this.seed = seed;
    38→  }
    39→
    40→  next(): number {
    41→    this.seed = (this.seed * 1103515245 + 12345) & 0x7fffffff;
    42→    return this.seed / 0x7fffffff;
    43→  }
    44→
    45→  range(min: number, max: number): number {
    46→    return Math.floor(this.next() * (max - min + 1)) + min;
    47→  }
    48→
    49→  pick<T>(array: T[]): T {
    50→    return array[this.range(0, array.length - 1)];
    51→  }
    52→
    53→  shuffle<T>(array: T[]): T[] {
    54→    const result = [...array];
    55→    for (let i = result.length - 1; i > 0; i--) {
    56→      const j = this.range(0, i);
    57→      [result[i], result[j]] = [result[j], result[i]];
    58→    }
    59→    return result;
    60→  }
    61→}
    62→
    63→/** Add days to a date */
    64→function addDays(date: Date, days: number): Date {
    65→  const result = new Date(date);
    66→  result.setDate(result.getDate() + days);
    67→  return result;
    68→}
    69→
    70→
    71→/** Days between two dates */
    72→function daysBetween(a: Date, b: Date): number {
    73→  const msPerDay = 24 * 60 * 60 * 1000;
    74→  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
    75→}
    76→
    77→/** Format date as YYYY-MM-DD */
    78→export function formatDate(date: Date): string {
    79→  return date.toISOString().split('T')[0];
    80→}
    81→
    82→/**
    83→ * Generate demo data for the MMS system
    84→ */
    85→export function generateDemoData(config: Partial<GeneratorConfig> = {}): GeneratedData {
    86→  const {
    87→    trainCount = 128,
    88→    historyYears = 5,
    89→    enableBowWave = false,
    90→    seed = Date.now(),
    91→  } = config;
    92→
    93→  const rng = new SeededRandom(seed);
    94→  const today = new Date();
    95→  today.setHours(0, 0, 0, 0);
    96→
    97→  const historyStartDate = addDays(today, -historyYears * 365);
    98→
    99→  // Generate depot IDs
   100→  const depots = DEMO_DEPOTS.map((d) => ({
   101→    id: uuidv4(),
   102→    code: d.code,
   103→    name: d.name,
   104→    location: d.location,
   105→    timezone: d.timezone,
   106→  }));
   107→
   108→  const depotByCode = new Map(depots.map((d) => [d.code, d]));
   109→
   110→  // Generate fleet IDs
   111→  const fleets = DEMO_FLEETS.map((f, index) => ({
   112→    id: uuidv4(),
   113→    code: f.code,
   114→    name: f.name,
   115→    manufacturer: f.manufacturer,
   116→    model: f.model,
   117→    baseDepotId: depots[index % depots.length].id,
   118→    carsPerTrain: f.carsPerTrain,
   119→  }));
   120→
   121→  const fleetByCode = new Map(fleets.map((f) => [f.code, f]));
   122→
   123→  // Generate PM types per fleet
   124→  const pmTypes: GeneratedData['pmTypes'] = [];
   125→  const pmTypeMap = new Map<string, { id: string; fleetId: string; intervalKm: number; intervalMonths: number }>();
   126→
   127→  for (const fleet of fleets) {
   128→    const rules = PM_RULES_BY_FLEET[fleet.code] || PM_RULES_BY_FLEET['ML'];
   129→    for (const rule of rules) {
   130→      const pmType = {
   131→        id: uuidv4(),
   132→        fleetId: fleet.id,
   133→        pmCode: rule.pmCode,
   134→        pmName: rule.pmName,
   135→        intervalKm: rule.intervalKm,
   136→        intervalMonths: rule.intervalMonths,
   137→        estimatedHours: rule.estimatedHours,
   138→        trackType: rule.trackType,
   139→        satisfiesCodes: rule.satisfiesCodes,
   140→        displayColor: rule.displayColor,
   141→        displayPriority: rule.displayPriority,
   142→      };
   143→      pmTypes.push(pmType);
   144→      pmTypeMap.set(`${fleet.code}:${rule.pmCode}`, {
   145→        id: pmType.id,
   146→        fleetId: fleet.id,
   147→        intervalKm: rule.intervalKm,
   148→        intervalMonths: rule.intervalMonths,
   149→      });
   150→    }
   151→  }
   152→
   153→  // Generate tracks
   154→  const tracks: GeneratedData['tracks'] = [];
   155→  for (const config of TRACK_CONFIGS) {
   156→    const depotCode = config.trackNumber.split('-')[0];
   157→    const depot = depotByCode.get(depotCode);
   158→    if (depot) {
   159→      tracks.push({
   160→        id: uuidv4(),
   161→        depotId: depot.id,
   162→        trackNumber: config.trackNumber,
   163→        trackType: config.trackType,
   164→        maxTrainLengthM: config.maxTrainLengthM,
   165→        hasOverheadCrane: config.hasOverheadCrane,
   166→        hasPitAccess: config.hasPitAccess,
   167→      });
   168→    }
   169→  }
   170→
   171→  // Calculate train distribution across fleets
   172→  const totalConfiguredTrains = DEMO_FLEETS.reduce((sum, f) => sum + f.trainCount, 0);
   173→  const scaleFactor = trainCount / totalConfiguredTrains;
   174→
   175→  // Generate trains
   176→  const trains: DemoTrain[] = [];
   177→
   178→  for (const fleetConfig of DEMO_FLEETS) {
   179→    const fleet = fleetByCode.get(fleetConfig.code)!;
   180→    const fleetTrainCount = Math.round(fleetConfig.trainCount * scaleFactor);
   181→
   182→    for (let i = 0; i < fleetTrainCount && trains.length < trainCount; i++) {
   183→
   184→      // Commissioning date: spread across the fleet's commissioning range
   185→      const commissioningRange =
   186→        fleetConfig.commissioningRange.end.getTime() - fleetConfig.commissioningRange.start.getTime();
   187→      const commissioningOffset = rng.next() * commissioningRange;
   188→      const commissioningDate = new Date(fleetConfig.commissioningRange.start.getTime() + commissioningOffset);
   189→
   190→      // Daily km varies per train (realistic operational variation)
   191→      const dailyKm = rng.range(fleetConfig.dailyKmRange.min, fleetConfig.dailyKmRange.max);
   192→
   193→      // Calculate current mileage based on days in service
   194→      const daysInService = daysBetween(commissioningDate, today);
   195→      // Add some variance to mileage (±15%)
   196→      const variance = 1 + (rng.next() - 0.5) * 0.3;
   197→      const currentMileageKm = Math.round(daysInService * dailyKm * variance);
   198→
   199→      // Fitness status: 90% FIT, 8% RESTRICTED, 2% GROUNDED
   200→      const fitnessRoll = rng.next();
   201→      const fitnessStatus =
   202→        fitnessRoll < 0.9 ? 'FIT' : fitnessRoll < 0.98 ? 'RESTRICTED' : 'GROUNDED';
   203→
   204→      trains.push({
   205→        id: uuidv4(),
   206→        fleetId: fleet.id,
   207→        fleetCode: fleetConfig.code,
   208→        trainNumber: `${fleetConfig.code}-${String(i + 1).padStart(3, '0')}`,
   209→        commissioningDate,
   210→        currentMileageKm,
   211→        estimatedDailyKm: dailyKm,
   212→        fitnessStatus,
   213→        displayColor: fleetConfig.displayColor,
   214→      });
   215→    }
   216→  }
   217→
   218→  // Generate PM history using cold-start algorithm
   219→  const pmHistory: DemoPMHistory[] = [];
   220→  const pmCodes = ['C1', 'C2', 'C3', 'C4', 'OH'];
   221→
   222→  for (const train of trains) {
   223→    // For each PM type, calculate completed cycles based on mileage
   224→    for (const pmCode of pmCodes) {
   225→      const pmTypeKey = `${train.fleetCode}:${pmCode}`;
   226→      const pmType = pmTypeMap.get(pmTypeKey);
   227→      if (!pmType) continue;
   228→
   229→      // Cold-start: Calculate cycles completed from commissioning
   230→      const cyclesCompleted = Math.floor(train.currentMileageKm / pmType.intervalKm);
   231→
   232→      // Generate history records for completed cycles
   233→      // Start from commissioning and work forward
   234→      let lastPmMileage = 0;
   235→      let lastPmDate = new Date(train.commissioningDate);
   236→
   237→      for (let cycle = 1; cycle <= cyclesCompleted; cycle++) {
   238→        const targetMileage = cycle * pmType.intervalKm;
   239→
   240→        // Calculate when this mileage was reached
   241→        const daysToReach = Math.round((targetMileage - lastPmMileage) / train.estimatedDailyKm);
   242→        const completionDate = addDays(lastPmDate, daysToReach);
   243→
   244→        // Only include history within the history window
   245→        if (completionDate >= historyStartDate && completionDate < today) {
   246→          // Add small variance to completion date (±3 days)
   247→          const dateVariance = rng.range(-3, 3);
   248→          const actualCompletionDate = addDays(completionDate, dateVariance);
   249→
   250→          // Add small variance to mileage (±2%)
   251→          const mileageVariance = 1 + (rng.next() - 0.5) * 0.04;
   252→          const actualMileage = Math.round(targetMileage * mileageVariance);
   253→
   254→          pmHistory.push({
   255→            trainId: train.id,
   256→            pmTypeId: pmType.id,
   257→            pmCode,
   258→            completionDate: actualCompletionDate,
   259→            completedMileageKm: actualMileage,
   260→          });
   261→        }
   262→
   263→        lastPmMileage = targetMileage;
   264→        lastPmDate = completionDate;
   265→      }
   266→    }
   267→  }
   268→
   269→  // Sort PM history by date
   270→  pmHistory.sort((a, b) => a.completionDate.getTime() - b.completionDate.getTime());
   271→
   272→  // Generate mileage readings (last 90 days only to limit data size)
   273→  const mileageReadings: DemoMileageReading[] = [];
   274→  const readingStartDate = addDays(today, -90);
   275→
   276→  for (const train of trains) {
   277→    // Calculate starting mileage for reading period
   278→    const daysToReadingStart = daysBetween(train.commissioningDate, readingStartDate);
   279→    let cumulativeMileage = Math.round(daysToReadingStart * train.estimatedDailyKm);
   280→
   281→    let currentDate = new Date(readingStartDate);
   282→    while (currentDate < today) {
   283→      // Daily km with variance
   284→      const dailyVariance = 0.8 + rng.next() * 0.4; // 80-120% of average
   285→      let dailyKm = Math.round(train.estimatedDailyKm * dailyVariance);
   286→
   287→      // Grounded trains don't accumulate mileage
   288→      if (train.fitnessStatus === 'GROUNDED') {
   289→        dailyKm = 0;
   290→      } else if (train.fitnessStatus === 'RESTRICTED') {
   291→        dailyKm = Math.round(dailyKm * 0.5); // 50% utilization when restricted
   292→      }
   293→
   294→      // Weekend reduction (15% less traffic)
   295→      const dayOfWeek = currentDate.getDay();
   296→      if (dayOfWeek === 0 || dayOfWeek === 6) {
   297→        dailyKm = Math.round(dailyKm * 0.85);
   298→      }
   299→
   300→      cumulativeMileage += dailyKm;
   301→
   302→      mileageReadings.push({
   303→        trainId: train.id,
   304→        readingDate: new Date(currentDate),
   305→        rawReading: cumulativeMileage,
   306→        adjustedReading: cumulativeMileage,
   307→        dailyKm,
   308→      });
   309→
   310→      currentDate = addDays(currentDate, 1);
   311→    }
   312→
   313→    // Update train's current mileage to match latest reading
   314→    train.currentMileageKm = cumulativeMileage;
   315→  }
   316→
   317→  // Generate service demand profiles
   318→  const serviceDemand: GeneratedData['serviceDemand'] = [];
   319→  for (const fleet of fleets) {
   320→    const fleetTrains = trains.filter((t) => t.fleetId === fleet.id);
   321→    const fleetSize = fleetTrains.length;
   322→
   323→    for (const profile of SERVICE_DEMAND_PROFILES) {
   324→      // Scale demand based on fleet size (roughly 70% of fleet for weekday min)
   325→      const scaleFactor = fleetSize / 48; // 48 is base fleet size
   326→      serviceDemand.push({
   327→        fleetId: fleet.id,
   328→        dayType: profile.dayType,
   329→        minTrainsRequired: Math.round(profile.minTrainsRequired * scaleFactor),
   330→        peakAmTrains: Math.round(profile.peakAmTrains * scaleFactor),
   331→        peakPmTrains: Math.round(profile.peakPmTrains * scaleFactor),
   332→      });
   333→    }
   334→  }
   335→
   336→  // Apply bow-wave scenario if enabled
   337→  if (enableBowWave) {
   338→    applyBowWaveScenario(trains, pmHistory, pmTypeMap, rng);
   339→  }
   340→
   341→  return {
   342→    depots,
   343→    fleets,
   344→    trains,
   345→    pmTypes,
   346→    pmHistory,
   347→    mileageReadings,
   348→    serviceDemand,
   349→    tracks,
   350→  };
   351→}
   352→
   353→/**
   354→ * Bow-Wave Scenario Generator (Chaos Monkey)
   355→ *
   356→ * Compresses 20% of fleet C4 maintenance into Q2 2027.
   357→ * Creates a realistic maintenance clustering scenario.
   358→ */
   359→function applyBowWaveScenario(
   360→  trains: DemoTrain[],
   361→  pmHistory: DemoPMHistory[],
   362→  pmTypeMap: Map<string, { id: string; fleetId: string; intervalKm: number; intervalMonths: number }>,
   363→  rng: SeededRandom
   364→): void {
   365→  const bowWaveStart = new Date('2027-04-01');
   366→  const bowWaveEnd = new Date('2027-06-30');
   367→
   368→  // Select 20% of trains for bow-wave
   369→  const shuffledTrains = rng.shuffle(trains);
   370→  const bowWaveTrains = shuffledTrains.slice(0, Math.ceil(trains.length * 0.2));
   371→
   372→  // For each bow-wave train, adjust their last C4 to cluster in Q2 2027
   373→  for (const train of bowWaveTrains) {
   374→    const pmTypeKey = `${train.fleetCode}:C4`;
   375→    const pmType = pmTypeMap.get(pmTypeKey);
   376→    if (!pmType) continue;
   377→
   378→    // Find train's C4 history
   379→    const trainC4History = pmHistory.filter(
   380→      (pm) => pm.trainId === train.id && pm.pmCode === 'C4'
   381→    );
   382→
   383→    if (trainC4History.length > 0) {
   384→      // Adjust the most recent C4 completion to create bow-wave
   385→      const lastC4 = trainC4History[trainC4History.length - 1];
   386→
   387→      // Shift last C4 so next one falls in Q2 2027
   388→      const bowWaveTargetDate = new Date(
   389→        bowWaveStart.getTime() + rng.next() * (bowWaveEnd.getTime() - bowWaveStart.getTime())
   390→      );
   391→
   392→      // Calculate when last C4 should have been completed
   393→      const daysUntilBowWave = daysBetween(new Date(), bowWaveTargetDate);
   394→      const mileageUntilBowWave = Math.round(daysUntilBowWave * train.estimatedDailyKm);
   395→      const adjustedLastC4Mileage = train.currentMileageKm + mileageUntilBowWave - pmType.intervalKm;
   396→
   397→      // Only adjust if it makes the history realistic
   398→      if (adjustedLastC4Mileage > 0) {
   399→        const daysToAdjustedMileage = Math.round(adjustedLastC4Mileage / train.estimatedDailyKm);
   400→        const adjustedCompletionDate = addDays(train.commissioningDate, daysToAdjustedMileage);
   401→
   402→        lastC4.completionDate = adjustedCompletionDate;
   403→        lastC4.completedMileageKm = adjustedLastC4Mileage;
   404→      }
   405→    }
   406→  }
   407→}
   408→
   409→/**
   410→ * Generate SQL INSERT statements for the demo data
   411→ */
   412→export function generateSQL(data: GeneratedData): string {
   413→  const lines: string[] = [];
   414→
   415→  lines.push('-- MMS Demo Data (Generated)');
   416→  lines.push(`-- Generated: ${new Date().toISOString()}`);
   417→  lines.push(`-- Trains: ${data.trains.length}`);
   418→  lines.push(`-- PM History Records: ${data.pmHistory.length}`);
   419→  lines.push(`-- Mileage Readings: ${data.mileageReadings.length}`);
   420→  lines.push('');
   421→  lines.push('-- CLEANUP');
   422→  lines.push('TRUNCATE TABLE pm_schedule, pm_types, mileage_readings, trains, fleets, depots CASCADE;');
   423→  lines.push('');
   424→
   425→  // Depots
   426→  lines.push('-- DEPOTS');
   427→  for (const depot of data.depots) {
   428→    lines.push(
   429→      `INSERT INTO depots (id, code, name, location, timezone) VALUES ('${depot.id}', '${depot.code}', '${depot.name}', '${depot.location}', '${depot.timezone}');`
   430→    );
   431→  }
   432→  lines.push('');
   433→
   434→  // Fleets
   435→  lines.push('-- FLEETS');
   436→  for (const fleet of data.fleets) {
   437→    lines.push(
   438→      `INSERT INTO fleets (id, code, name, manufacturer, model, base_depot_id, cars_per_train) VALUES ('${fleet.id}', '${fleet.code}', '${fleet.name}', '${fleet.manufacturer}', '${fleet.model}', '${fleet.baseDepotId}', ${fleet.carsPerTrain});`
   439→    );
   440→  }
   441→  lines.push('');
   442→
   443→  // Trains
   444→  lines.push('-- TRAINS');
   445→  for (const train of data.trains) {
   446→    lines.push(
   447→      `INSERT INTO trains (id, fleet_id, train_number, commissioning_date, current_mileage_km, fitness_status, display_color) VALUES ('${train.id}', '${train.fleetId}', '${train.trainNumber}', '${formatDate(train.commissioningDate)}', ${train.currentMileageKm}, '${train.fitnessStatus}', '${train.displayColor}');`
   448→    );
   449→  }
   450→  lines.push('');
   451→
   452→  // PM Types
   453→  lines.push('-- PM TYPES');
   454→  for (const pmType of data.pmTypes) {
   455→    const satisfies = pmType.satisfiesCodes
   456→      ? `ARRAY[${pmType.satisfiesCodes.map((c) => `'${c}'`).join(', ')}]::TEXT[]`
   457→      : 'NULL';
   458→    lines.push(
   459→      `INSERT INTO pm_types (id, fleet_id, pm_code, pm_name, interval_km, interval_months, estimated_hours, track_type, satisfies_codes, display_color, display_priority) VALUES ('${pmType.id}', '${pmType.fleetId}', '${pmType.pmCode}', '${pmType.pmName}', ${pmType.intervalKm}, ${pmType.intervalMonths}, ${pmType.estimatedHours}, '${pmType.trackType}', ${satisfies}, '${pmType.displayColor}', ${pmType.displayPriority});`
   460→    );
   461→  }
   462→  lines.push('');
   463→
   464→  // Tracks
   465→  lines.push('-- TRACKS');
   466→  for (const track of data.tracks) {
   467→    lines.push(
   468→      `INSERT INTO tracks (id, depot_id, track_number, track_type, max_train_length_m, has_overhead_crane, has_pit_access) VALUES ('${track.id}', '${track.depotId}', '${track.trackNumber}', '${track.trackType}', ${track.maxTrainLengthM}, ${track.hasOverheadCrane}, ${track.hasPitAccess});`
   469→    );
   470→  }
   471→  lines.push('');
   472→
   473→  // PM History (as completed PM schedule entries)
   474→  lines.push('-- PM HISTORY (Completed PMs)');
   475→  for (const pm of data.pmHistory) {
   476→    const constraintStart = formatDate(addDays(pm.completionDate, -14));
   477→    const constraintEnd = formatDate(addDays(pm.completionDate, 14));
   478→    lines.push(
   479→      `INSERT INTO pm_schedule (id, train_id, pm_type_id, target_date, status, constraint_start, constraint_end, completed_at, completed_mileage_km) VALUES ('${uuidv4()}', '${pm.trainId}', '${pm.pmTypeId}', '${formatDate(pm.completionDate)}', 'COMPLETED', '${constraintStart}', '${constraintEnd}', '${pm.completionDate.toISOString()}', ${pm.completedMileageKm});`
   480→    );
   481→  }
   482→  lines.push('');
   483→
   484→  // Mileage Readings (batch insert for performance)
   485→  lines.push('-- MILEAGE READINGS');
   486→  const BATCH_SIZE = 100;
   487→  for (let i = 0; i < data.mileageReadings.length; i += BATCH_SIZE) {
   488→    const batch = data.mileageReadings.slice(i, i + BATCH_SIZE);
   489→    const values = batch
   490→      .map(
   491→        (r) =>
   492→          `('${r.trainId}', '${formatDate(r.readingDate)}', ${r.rawReading}, ${r.adjustedReading}, ${r.dailyKm}, 'VALID')`
   493→      )
   494→      .join(',\n  ');
   495→    lines.push(
   496→      `INSERT INTO mileage_readings (train_id, reading_date, raw_reading, adjusted_reading, daily_km, validation_status) VALUES\n  ${values};`
   497→    );
   498→  }
   499→  lines.push('');
   500→
   501→  // Service Demand
   502→  lines.push('-- SERVICE DEMAND');
   503→  for (const demand of data.serviceDemand) {
   504→    lines.push(
   505→      `INSERT INTO service_demand (id, fleet_id, day_type, min_trains_required, peak_am_trains, peak_pm_trains) VALUES ('${uuidv4()}', '${demand.fleetId}', '${demand.dayType}', ${demand.minTrainsRequired}, ${demand.peakAmTrains}, ${demand.peakPmTrains});`
   506→    );
   507→  }
   508→  lines.push('');
   509→
   510→  lines.push('-- VERIFICATION');
   511→  lines.push(`DO $$`);
   512→  lines.push(`DECLARE`);
   513→  lines.push(`    train_count INTEGER;`);
   514→  lines.push(`    pm_count INTEGER;`);
   515→  lines.push(`    reading_count INTEGER;`);
   516→  lines.push(`BEGIN`);
   517→  lines.push(`    SELECT COUNT(*) INTO train_count FROM trains;`);
   518→  lines.push(`    SELECT COUNT(*) INTO pm_count FROM pm_schedule;`);
   519→  lines.push(`    SELECT COUNT(*) INTO reading_count FROM mileage_readings;`);
   520→  lines.push(`    RAISE NOTICE 'Demo data loaded:';`);
   521→  lines.push(`    RAISE NOTICE '  - Trains: %', train_count;`);
   522→  lines.push(`    RAISE NOTICE '  - PM Schedule entries: %', pm_count;`);
   523→  lines.push(`    RAISE NOTICE '  - Mileage readings: %', reading_count;`);
   524→  lines.push(`END $$;`);
   525→
   526→  return lines.join('\n');
   527→}
