/**
 * MMS Demo Data Generator
 *
 * Generates realistic fleet data for the MMS demo application.
 * Creates 128 trains across 3 fleets with 5+ years of historical data.
 *
 * Key features:
 * - Cold-start algorithm for trains with no PM history
 * - PM hierarchy cascade (C4 satisfies C1/C2/C3)
 * - Dual triggers (mileage + time-based)
 * - Bow-wave scenario generator (Chaos Monkey)
 *
 * @see specs/009-demo-application.md
 */

import { v4 as uuidv4 } from 'uuid';
import {
  DEMO_DEPOTS,
  DEMO_FLEETS,
  PM_RULES_BY_FLEET,
  SERVICE_DEMAND_PROFILES,
  TRACK_CONFIGS,
} from './data';
import type {
  DemoMileageReading,
  DemoPMHistory,
  DemoTrain,
  GeneratedData,
  GeneratorConfig,
} from './types';

/** Seeded random number generator for reproducible results */
class SeededRandom {
  private seed: number;

  constructor(seed: number) {
    this.seed = seed;
  }

  next(): number {
    this.seed = (this.seed * 1103515245 + 12345) & 0x7fffffff;
    return this.seed / 0x7fffffff;
  }

  range(min: number, max: number): number {
    return Math.floor(this.next() * (max - min + 1)) + min;
  }

  pick<T>(array: T[]): T {
    return array[this.range(0, array.length - 1)];
  }

  shuffle<T>(array: T[]): T[] {
    const result = [...array];
    for (let i = result.length - 1; i > 0; i--) {
      const j = this.range(0, i);
      [result[i], result[j]] = [result[j], result[i]];
    }
    return result;
  }
}

/** Add days to a date */
function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}


/** Days between two dates */
function daysBetween(a: Date, b: Date): number {
  const msPerDay = 24 * 60 * 60 * 1000;
  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
}

/** Format date as YYYY-MM-DD */
export function formatDate(date: Date): string {
  return date.toISOString().split('T')[0];
}

/**
 * Generate demo data for the MMS system
 */
export function generateDemoData(config: Partial<GeneratorConfig> = {}): GeneratedData {
  const {
    trainCount = 128,
    historyYears = 5,
    enableBowWave = false,
    seed = Date.now(),
  } = config;

  const rng = new SeededRandom(seed);
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const historyStartDate = addDays(today, -historyYears * 365);

  // Generate depot IDs
  const depots = DEMO_DEPOTS.map((d) => ({
    id: uuidv4(),
    code: d.code,
    name: d.name,
    location: d.location,
    timezone: d.timezone,
  }));

  const depotByCode = new Map(depots.map((d) => [d.code, d]));

  // Generate fleet IDs
  const fleets = DEMO_FLEETS.map((f, index) => ({
    id: uuidv4(),
    code: f.code,
    name: f.name,
    manufacturer: f.manufacturer,
    model: f.model,
    baseDepotId: depots[index % depots.length].id,
    carsPerTrain: f.carsPerTrain,
  }));

  const fleetByCode = new Map(fleets.map((f) => [f.code, f]));

  // Generate PM types per fleet
  const pmTypes: GeneratedData['pmTypes'] = [];
  const pmTypeMap = new Map<string, { id: string; fleetId: string; intervalKm: number; intervalMonths: number }>();

  for (const fleet of fleets) {
    const rules = PM_RULES_BY_FLEET[fleet.code] || PM_RULES_BY_FLEET['ML'];
    for (const rule of rules) {
      const pmType = {
        id: uuidv4(),
        fleetId: fleet.id,
        pmCode: rule.pmCode,
        pmName: rule.pmName,
        intervalKm: rule.intervalKm,
        intervalMonths: rule.intervalMonths,
        estimatedHours: rule.estimatedHours,
        trackType: rule.trackType,
        satisfiesCodes: rule.satisfiesCodes,
        displayColor: rule.displayColor,
        displayPriority: rule.displayPriority,
      };
      pmTypes.push(pmType);
      pmTypeMap.set(`${fleet.code}:${rule.pmCode}`, {
        id: pmType.id,
        fleetId: fleet.id,
        intervalKm: rule.intervalKm,
        intervalMonths: rule.intervalMonths,
      });
    }
  }

  // Generate tracks
  const tracks: GeneratedData['tracks'] = [];
  for (const config of TRACK_CONFIGS) {
    const depotCode = config.trackNumber.split('-')[0];
    const depot = depotByCode.get(depotCode);
    if (depot) {
      tracks.push({
        id: uuidv4(),
        depotId: depot.id,
        trackNumber: config.trackNumber,
        trackType: config.trackType,
        maxTrainLengthM: config.maxTrainLengthM,
        hasOverheadCrane: config.hasOverheadCrane,
        hasPitAccess: config.hasPitAccess,
      });
    }
  }

  // Calculate train distribution across fleets
  const totalConfiguredTrains = DEMO_FLEETS.reduce((sum, f) => sum + f.trainCount, 0);
  const scaleFactor = trainCount / totalConfiguredTrains;

  // Generate trains
  const trains: DemoTrain[] = [];

  for (const fleetConfig of DEMO_FLEETS) {
    const fleet = fleetByCode.get(fleetConfig.code)!;
    const fleetTrainCount = Math.round(fleetConfig.trainCount * scaleFactor);

    for (let i = 0; i < fleetTrainCount && trains.length < trainCount; i++) {

      // Commissioning date: spread across the fleet's commissioning range
      const commissioningRange =
        fleetConfig.commissioningRange.end.getTime() - fleetConfig.commissioningRange.start.getTime();
      const commissioningOffset = rng.next() * commissioningRange;
      const commissioningDate = new Date(fleetConfig.commissioningRange.start.getTime() + commissioningOffset);

      // Daily km varies per train (realistic operational variation)
      const dailyKm = rng.range(fleetConfig.dailyKmRange.min, fleetConfig.dailyKmRange.max);

      // Calculate current mileage based on days in service
      const daysInService = daysBetween(commissioningDate, today);
      // Add some variance to mileage (±15%)
      const variance = 1 + (rng.next() - 0.5) * 0.3;
      const currentMileageKm = Math.round(daysInService * dailyKm * variance);

      // Fitness status: 90% FIT, 8% RESTRICTED, 2% GROUNDED
      const fitnessRoll = rng.next();
      const fitnessStatus =
        fitnessRoll < 0.9 ? 'FIT' : fitnessRoll < 0.98 ? 'RESTRICTED' : 'GROUNDED';

      trains.push({
        id: uuidv4(),
        fleetId: fleet.id,
        fleetCode: fleetConfig.code,
        trainNumber: `${fleetConfig.code}-${String(i + 1).padStart(3, '0')}`,
        commissioningDate,
        currentMileageKm,
        estimatedDailyKm: dailyKm,
        fitnessStatus,
        displayColor: fleetConfig.displayColor,
      });
    }
  }

  // Generate PM history using cold-start algorithm
  const pmHistory: DemoPMHistory[] = [];
  const pmCodes = ['C1', 'C2', 'C3', 'C4', 'OH'];

  for (const train of trains) {
    // For each PM type, calculate completed cycles based on mileage
    for (const pmCode of pmCodes) {
      const pmTypeKey = `${train.fleetCode}:${pmCode}`;
      const pmType = pmTypeMap.get(pmTypeKey);
      if (!pmType) continue;

      // Cold-start: Calculate cycles completed from commissioning
      const cyclesCompleted = Math.floor(train.currentMileageKm / pmType.intervalKm);

      // Generate history records for completed cycles
      // Start from commissioning and work forward
      let lastPmMileage = 0;
      let lastPmDate = new Date(train.commissioningDate);

      for (let cycle = 1; cycle <= cyclesCompleted; cycle++) {
        const targetMileage = cycle * pmType.intervalKm;

        // Calculate when this mileage was reached
        const daysToReach = Math.round((targetMileage - lastPmMileage) / train.estimatedDailyKm);
        const completionDate = addDays(lastPmDate, daysToReach);

        // Only include history within the history window
        if (completionDate >= historyStartDate && completionDate < today) {
          // Add small variance to completion date (±3 days)
          const dateVariance = rng.range(-3, 3);
          const actualCompletionDate = addDays(completionDate, dateVariance);

          // Add small variance to mileage (±2%)
          const mileageVariance = 1 + (rng.next() - 0.5) * 0.04;
          const actualMileage = Math.round(targetMileage * mileageVariance);

          pmHistory.push({
            trainId: train.id,
            pmTypeId: pmType.id,
            pmCode,
            completionDate: actualCompletionDate,
            completedMileageKm: actualMileage,
          });
        }

        lastPmMileage = targetMileage;
        lastPmDate = completionDate;
      }
    }
  }

  // Sort PM history by date
  pmHistory.sort((a, b) => a.completionDate.getTime() - b.completionDate.getTime());

  // Generate mileage readings (last 90 days only to limit data size)
  const mileageReadings: DemoMileageReading[] = [];
  const readingStartDate = addDays(today, -90);

  for (const train of trains) {
    // Calculate starting mileage for reading period
    const daysToReadingStart = daysBetween(train.commissioningDate, readingStartDate);
    let cumulativeMileage = Math.round(daysToReadingStart * train.estimatedDailyKm);

    let currentDate = new Date(readingStartDate);
    while (currentDate < today) {
      // Daily km with variance
      const dailyVariance = 0.8 + rng.next() * 0.4; // 80-120% of average
      let dailyKm = Math.round(train.estimatedDailyKm * dailyVariance);

      // Grounded trains don't accumulate mileage
      if (train.fitnessStatus === 'GROUNDED') {
        dailyKm = 0;
      } else if (train.fitnessStatus === 'RESTRICTED') {
        dailyKm = Math.round(dailyKm * 0.5); // 50% utilization when restricted
      }

      // Weekend reduction (15% less traffic)
      const dayOfWeek = currentDate.getDay();
      if (dayOfWeek === 0 || dayOfWeek === 6) {
        dailyKm = Math.round(dailyKm * 0.85);
      }

      cumulativeMileage += dailyKm;

      mileageReadings.push({
        trainId: train.id,
        readingDate: new Date(currentDate),
        rawReading: cumulativeMileage,
        adjustedReading: cumulativeMileage,
        dailyKm,
      });

      currentDate = addDays(currentDate, 1);
    }

    // Update train's current mileage to match latest reading
    train.currentMileageKm = cumulativeMileage;
  }

  // Generate service demand profiles
  const serviceDemand: GeneratedData['serviceDemand'] = [];
  for (const fleet of fleets) {
    const fleetTrains = trains.filter((t) => t.fleetId === fleet.id);
    const fleetSize = fleetTrains.length;

    for (const profile of SERVICE_DEMAND_PROFILES) {
      // Scale demand based on fleet size (roughly 70% of fleet for weekday min)
      const scaleFactor = fleetSize / 48; // 48 is base fleet size
      serviceDemand.push({
        fleetId: fleet.id,
        dayType: profile.dayType,
        minTrainsRequired: Math.round(profile.minTrainsRequired * scaleFactor),
        peakAmTrains: Math.round(profile.peakAmTrains * scaleFactor),
        peakPmTrains: Math.round(profile.peakPmTrains * scaleFactor),
      });
    }
  }

  // Apply bow-wave scenario if enabled
  if (enableBowWave) {
    applyBowWaveScenario(trains, pmHistory, pmTypeMap, rng);
  }

  return {
    depots,
    fleets,
    trains,
    pmTypes,
    pmHistory,
    mileageReadings,
    serviceDemand,
    tracks,
  };
}

/**
 * Bow-Wave Scenario Generator (Chaos Monkey)
 *
 * Compresses 20% of fleet C4 maintenance into Q2 2027.
 * Creates a realistic maintenance clustering scenario.
 */
function applyBowWaveScenario(
  trains: DemoTrain[],
  pmHistory: DemoPMHistory[],
  pmTypeMap: Map<string, { id: string; fleetId: string; intervalKm: number; intervalMonths: number }>,
  rng: SeededRandom
): void {
  const bowWaveStart = new Date('2027-04-01');
  const bowWaveEnd = new Date('2027-06-30');

  // Select 20% of trains for bow-wave
  const shuffledTrains = rng.shuffle(trains);
  const bowWaveTrains = shuffledTrains.slice(0, Math.ceil(trains.length * 0.2));

  // For each bow-wave train, adjust their last C4 to cluster in Q2 2027
  for (const train of bowWaveTrains) {
    const pmTypeKey = `${train.fleetCode}:C4`;
    const pmType = pmTypeMap.get(pmTypeKey);
    if (!pmType) continue;

    // Find train's C4 history
    const trainC4History = pmHistory.filter(
      (pm) => pm.trainId === train.id && pm.pmCode === 'C4'
    );

    if (trainC4History.length > 0) {
      // Adjust the most recent C4 completion to create bow-wave
      const lastC4 = trainC4History[trainC4History.length - 1];

      // Shift last C4 so next one falls in Q2 2027
      const bowWaveTargetDate = new Date(
        bowWaveStart.getTime() + rng.next() * (bowWaveEnd.getTime() - bowWaveStart.getTime())
      );

      // Calculate when last C4 should have been completed
      const daysUntilBowWave = daysBetween(new Date(), bowWaveTargetDate);
      const mileageUntilBowWave = Math.round(daysUntilBowWave * train.estimatedDailyKm);
      const adjustedLastC4Mileage = train.currentMileageKm + mileageUntilBowWave - pmType.intervalKm;

      // Only adjust if it makes the history realistic
      if (adjustedLastC4Mileage > 0) {
        const daysToAdjustedMileage = Math.round(adjustedLastC4Mileage / train.estimatedDailyKm);
        const adjustedCompletionDate = addDays(train.commissioningDate, daysToAdjustedMileage);

        lastC4.completionDate = adjustedCompletionDate;
        lastC4.completedMileageKm = adjustedLastC4Mileage;
      }
    }
  }
}

/**
 * Generate SQL INSERT statements for the demo data
 */
export function generateSQL(data: GeneratedData): string {
  const lines: string[] = [];

  lines.push('-- MMS Demo Data (Generated)');
  lines.push(`-- Generated: ${new Date().toISOString()}`);
  lines.push(`-- Trains: ${data.trains.length}`);
  lines.push(`-- PM History Records: ${data.pmHistory.length}`);
  lines.push(`-- Mileage Readings: ${data.mileageReadings.length}`);
  lines.push('');
  lines.push('-- CLEANUP');
  lines.push('TRUNCATE TABLE pm_schedule, pm_types, mileage_readings, trains, fleets, depots CASCADE;');
  lines.push('');

  // Depots
  lines.push('-- DEPOTS');
  for (const depot of data.depots) {
    lines.push(
      `INSERT INTO depots (id, code, name, location, timezone) VALUES ('${depot.id}', '${depot.code}', '${depot.name}', '${depot.location}', '${depot.timezone}');`
    );
  }
  lines.push('');

  // Fleets
  lines.push('-- FLEETS');
  for (const fleet of data.fleets) {
    lines.push(
      `INSERT INTO fleets (id, code, name, manufacturer, model, base_depot_id, cars_per_train) VALUES ('${fleet.id}', '${fleet.code}', '${fleet.name}', '${fleet.manufacturer}', '${fleet.model}', '${fleet.baseDepotId}', ${fleet.carsPerTrain});`
    );
  }
  lines.push('');

  // Trains
  lines.push('-- TRAINS');
  for (const train of data.trains) {
    lines.push(
      `INSERT INTO trains (id, fleet_id, train_number, commissioning_date, current_mileage_km, fitness_status, display_color) VALUES ('${train.id}', '${train.fleetId}', '${train.trainNumber}', '${formatDate(train.commissioningDate)}', ${train.currentMileageKm}, '${train.fitnessStatus}', '${train.displayColor}');`
    );
  }
  lines.push('');

  // PM Types
  lines.push('-- PM TYPES');
  for (const pmType of data.pmTypes) {
    const satisfies = pmType.satisfiesCodes
      ? `ARRAY[${pmType.satisfiesCodes.map((c) => `'${c}'`).join(', ')}]::TEXT[]`
      : 'NULL';
    lines.push(
      `INSERT INTO pm_types (id, fleet_id, pm_code, pm_name, interval_km, interval_months, estimated_hours, track_type, satisfies_codes, display_color, display_priority) VALUES ('${pmType.id}', '${pmType.fleetId}', '${pmType.pmCode}', '${pmType.pmName}', ${pmType.intervalKm}, ${pmType.intervalMonths}, ${pmType.estimatedHours}, '${pmType.trackType}', ${satisfies}, '${pmType.displayColor}', ${pmType.displayPriority});`
    );
  }
  lines.push('');

  // Tracks
  lines.push('-- TRACKS');
  for (const track of data.tracks) {
    lines.push(
      `INSERT INTO tracks (id, depot_id, track_number, track_type, max_train_length_m, has_overhead_crane, has_pit_access) VALUES ('${track.id}', '${track.depotId}', '${track.trackNumber}', '${track.trackType}', ${track.maxTrainLengthM}, ${track.hasOverheadCrane}, ${track.hasPitAccess});`
    );
  }
  lines.push('');

  // PM History (as completed PM schedule entries)
  lines.push('-- PM HISTORY (Completed PMs)');
  for (const pm of data.pmHistory) {
    const constraintStart = formatDate(addDays(pm.completionDate, -14));
    const constraintEnd = formatDate(addDays(pm.completionDate, 14));
    lines.push(
      `INSERT INTO pm_schedule (id, train_id, pm_type_id, target_date, status, constraint_start, constraint_end, completed_at, completed_mileage_km) VALUES ('${uuidv4()}', '${pm.trainId}', '${pm.pmTypeId}', '${formatDate(pm.completionDate)}', 'COMPLETED', '${constraintStart}', '${constraintEnd}', '${pm.completionDate.toISOString()}', ${pm.completedMileageKm});`
    );
  }
  lines.push('');

  // Mileage Readings (batch insert for performance)
  lines.push('-- MILEAGE READINGS');
  const BATCH_SIZE = 100;
  for (let i = 0; i < data.mileageReadings.length; i += BATCH_SIZE) {
    const batch = data.mileageReadings.slice(i, i + BATCH_SIZE);
    const values = batch
      .map(
        (r) =>
          `('${r.trainId}', '${formatDate(r.readingDate)}', ${r.rawReading}, ${r.adjustedReading}, ${r.dailyKm}, 'VALID')`
      )
      .join(',\n  ');
    lines.push(
      `INSERT INTO mileage_readings (train_id, reading_date, raw_reading, adjusted_reading, daily_km, validation_status) VALUES\n  ${values};`
    );
  }
  lines.push('');

  // Service Demand
  lines.push('-- SERVICE DEMAND');
  for (const demand of data.serviceDemand) {
    lines.push(
      `INSERT INTO service_demand (id, fleet_id, day_type, min_trains_required, peak_am_trains, peak_pm_trains) VALUES ('${uuidv4()}', '${demand.fleetId}', '${demand.dayType}', ${demand.minTrainsRequired}, ${demand.peakAmTrains}, ${demand.peakPmTrains});`
    );
  }
  lines.push('');

  lines.push('-- VERIFICATION');
  lines.push(`DO $$`);
  lines.push(`DECLARE`);
  lines.push(`    train_count INTEGER;`);
  lines.push(`    pm_count INTEGER;`);
  lines.push(`    reading_count INTEGER;`);
  lines.push(`BEGIN`);
  lines.push(`    SELECT COUNT(*) INTO train_count FROM trains;`);
  lines.push(`    SELECT COUNT(*) INTO pm_count FROM pm_schedule;`);
  lines.push(`    SELECT COUNT(*) INTO reading_count FROM mileage_readings;`);
  lines.push(`    RAISE NOTICE 'Demo data loaded:';`);
  lines.push(`    RAISE NOTICE '  - Trains: %', train_count;`);
  lines.push(`    RAISE NOTICE '  - PM Schedule entries: %', pm_count;`);
  lines.push(`    RAISE NOTICE '  - Mileage readings: %', reading_count;`);
  lines.push(`END $$;`);

  return lines.join('\n');
}

