    28→
    29→/** Weekly man-hour capacity (40 hours x 5 technicians) */
    30→const WEEKLY_MAN_HOUR_CAPACITY = 200;
    31→
    32→/** Critical threshold: >15 PMs per month */
    33→const CRITICAL_PM_THRESHOLD = 15;
    34→
    35→/** Overlap violation threshold: 40% of fleet */
    36→const OVERLAP_VIOLATION_THRESHOLD = 0.4;
    37→
    38→/** Add days to a date */
    39→function addDays(date: Date, days: number): Date {
    40→  const result = new Date(date);
    41→  result.setDate(result.getDate() + days);
    42→  return result;
    43→}
    44→
    45→/** Get year-month string from date */
    46→function getYearMonth(date: Date): string {
    47→  const year = date.getFullYear();
    48→  const month = String(date.getMonth() + 1).padStart(2, '0');
    49→  return `${year}-${month}`;
    50→}
    51→
    52→/** Get quarter string from date (Q1-Q4 YYYY) */
    53→function getQuarter(date: Date): string {
    54→  const year = date.getFullYear();
    55→  const quarter = Math.floor(date.getMonth() / 3) + 1;
    56→  return `Q${quarter} ${year}`;
    57→}
    58→
    59→/** Calculate days between two dates */
    60→function daysBetween(a: Date, b: Date): number {
    61→  const msPerDay = 24 * 60 * 60 * 1000;
    62→  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
    63→}
    64→
    65→interface PmTypeInfo {
    66→  id: string;
    67→  pmCode: string;
    68→  intervalKm: number;
    69→  intervalMonths: number;
    70→  estimatedHours: number;
    71→  displayColor: string;
    72→}
    73→
    74→/**
    75→ * Project future PM events for a train based on current state and history
    76→ */
    77→function projectTrainPMs(
    78→  train: DemoTrain,
    79→  pmTypes: PmTypeInfo[],
    80→  pmHistory: DemoPMHistory[],
    81→  horizonDate: Date,
    82→  today: Date
    83→): ProjectedPM[] {
    84→  const projections: ProjectedPM[] = [];
    85→
    86→  // Get train's PM history
    87→  const trainHistory = pmHistory.filter((pm) => pm.trainId === train.id);
    88→
    89→  for (const pmType of pmTypes) {
    90→    // Find the most recent completion of this PM type
    91→    const lastCompletion = trainHistory
    92→      .filter((pm) => pm.pmTypeId === pmType.id)
    93→      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime())[0];
    94→
    95→    // Calculate next due date using dual triggers (mileage and time)
    96→    let nextDueDate: Date;
    97→    let nextDueMileage: number;
    98→
    99→    if (lastCompletion) {
   100→      // Calculate from last completion
   101→      const mileageSinceCompletion = train.currentMileageKm - lastCompletion.completedMileageKm;
   102→      const kmToNextPm = pmType.intervalKm - mileageSinceCompletion;
   103→      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));
   104→
   105→      const daysSinceCompletion = daysBetween(lastCompletion.completionDate, today);
   106→      const daysToTimeDue = Math.max(0, pmType.intervalMonths * 30 - daysSinceCompletion);
   107→
   108→      // Dual trigger: whichever comes first
   109→      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
   110→      nextDueDate = addDays(today, daysToNextPm);
   111→      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
   112→    } else {
   113→      // Cold start: assume PM was done at commissioning on-schedule
   114→      const daysSinceCommissioning = daysBetween(train.commissioningDate, today);
   115→      const cyclesFromCommissioning = Math.floor(train.currentMileageKm / pmType.intervalKm);
   116→      const lastPmMileage = cyclesFromCommissioning * pmType.intervalKm;
   117→
   118→      const kmToNextPm = pmType.intervalKm - (train.currentMileageKm - lastPmMileage);
   119→      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));
   120→
   121→      const monthsIntoCurrentCycle = (daysSinceCommissioning / 30) % pmType.intervalMonths;
   122→      const daysToTimeDue = Math.max(0, (pmType.intervalMonths - monthsIntoCurrentCycle) * 30);
   123→
   124→      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
   125→      nextDueDate = addDays(today, daysToNextPm);
   126→      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
   127→    }
   128→
   129→    // Project all PMs within horizon
   130→    let currentDate = nextDueDate;
   131→    let currentMileage = nextDueMileage;
   132→
   133→    while (currentDate <= horizonDate) {
   134→      projections.push({
   135→        trainId: train.id,
   136→        trainNumber: train.trainNumber,
   137→        fleetCode: train.fleetCode,
   138→        pmTypeId: pmType.id,
   139→        pmCode: pmType.pmCode,
   140→        projectedDate: new Date(currentDate),
   141→        projectedMileage: Math.round(currentMileage),
   142→        estimatedHours: pmType.estimatedHours,
   143→        displayColor: pmType.displayColor,
   144→      });
   145→
   146→      // Calculate next interval
   147→      const intervalDays = Math.round(pmType.intervalKm / train.estimatedDailyKm);
   148→      const timeDays = pmType.intervalMonths * 30;
   149→      const nextInterval = Math.min(intervalDays, timeDays);
   150→
   151→      currentDate = addDays(currentDate, nextInterval);
   152→      currentMileage += nextInterval * train.estimatedDailyKm;
   153→    }
   154→  }
   155→
   156→  return projections;
   157→}
   158→
   159→/**
   160→ * Calculate monthly PM density for heatmap visualization
   161→ */
   162→function calculateMonthlyDensity(projections: ProjectedPM[]): MonthlyPMDensity[] {
   163→  const densityMap = new Map<string, MonthlyPMDensity>();
   164→
   165→  for (const pm of projections) {
   166→    const yearMonth = getYearMonth(pm.projectedDate);
   167→
   168→    if (!densityMap.has(yearMonth)) {
   169→      densityMap.set(yearMonth, {
   170→        year: pm.projectedDate.getFullYear(),
   171→        month: pm.projectedDate.getMonth() + 1,
   172→        yearMonth,
   173→        totalPMs: 0,
   174→        pmsByType: {},
   175→        isCritical: false,
   176→        manHours: 0,
   177→      });
   178→    }
   179→
   180→    const density = densityMap.get(yearMonth)!;
   181→    density.totalPMs++;
   182→    density.pmsByType[pm.pmCode] = (density.pmsByType[pm.pmCode] || 0) + 1;
   183→    density.manHours += pm.estimatedHours;
   184→  }
   185→
   186→  // Mark critical months (>15 PMs)
   187→  for (const density of densityMap.values()) {
   188→    density.isCritical = density.totalPMs > CRITICAL_PM_THRESHOLD;
   189→  }
   190→
   191→  return Array.from(densityMap.values()).sort((a, b) => a.yearMonth.localeCompare(b.yearMonth));
   192→}
   193→
   194→/**
   195→ * Generate Gantt bar data for tactical visualization
   196→ */
   197→function generateGanttBars(projections: ProjectedPM[]): GanttBar[] {
   198→  return projections.map((pm) => {
   199→    // Estimate duration in days based on hours (8 hour workday)
