   214→}
   215→
   216→/**
   217→ * Analyze bow-wave scenario from projected PMs
   218→ */
   219→function analyzeBowWave(projections: ProjectedPM[], fleetSize: number): BowWaveAnalysis {
   220→  // Group C4 PMs by month and quarter
   221→  const c4Projections = projections.filter((pm) => pm.pmCode === 'C4');
   222→
   223→  const c4ByMonth = new Map<string, ProjectedPM[]>();
   224→  const c4ByQuarter = new Map<string, ProjectedPM[]>();
   225→
   226→  for (const pm of c4Projections) {
   227→    const yearMonth = getYearMonth(pm.projectedDate);
   228→    const quarter = getQuarter(pm.projectedDate);
   229→
   230→    if (!c4ByMonth.has(yearMonth)) {
   231→      c4ByMonth.set(yearMonth, []);
   232→    }
   233→    c4ByMonth.get(yearMonth)!.push(pm);
   234→
   235→    if (!c4ByQuarter.has(quarter)) {
   236→      c4ByQuarter.set(quarter, []);
   237→    }
   238→    c4ByQuarter.get(quarter)!.push(pm);
   239→  }
   240→
   241→  // Find peak month
   242→  let peakMonthKey = '';
   243→  let peakMonthCount = 0;
   244→  for (const [month, pms] of c4ByMonth) {
   245→    // Count unique trains
   246→    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
   247→    if (uniqueTrains > peakMonthCount) {
   248→      peakMonthCount = uniqueTrains;
   249→      peakMonthKey = month;
   250→    }
   251→  }
   252→
   253→  // Find peak quarter
   254→  let peakQuarterKey = '';
   255→  let peakQuarterCount = 0;
   256→  for (const [quarter, pms] of c4ByQuarter) {
   257→    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
   258→    if (uniqueTrains > peakQuarterCount) {
   259→      peakQuarterCount = uniqueTrains;
   260→      peakQuarterKey = quarter;
   261→    }
   262→  }
   263→
   264→  // Calculate percentages
   265→  const peakMonthPercentage = fleetSize > 0 ? (peakMonthCount / fleetSize) * 100 : 0;
   266→  const peakQuarterPercentage = fleetSize > 0 ? (peakQuarterCount / fleetSize) * 100 : 0;
   267→
   268→  // Check for 40% overlap violation
   269→  const hasOverlapViolation = peakMonthPercentage >= OVERLAP_VIOLATION_THRESHOLD * 100;
   270→
   271→  // Count affected trains (those with C4 in peak quarter)
   272→  const affectedTrainIds = peakQuarterKey
   273→    ? new Set(c4ByQuarter.get(peakQuarterKey)?.map((pm) => pm.trainId) || [])
   274→    : new Set<string>();
   275→
   276→  // Calculate capital risk (C4 count in peak quarter x cost per C4)
   277→  const capitalRiskMillions = peakQuarterCount * C4_COST_MILLIONS;
   278→
   279→  // Calculate man-hour capacity analysis for peak week
   280→  const peakMonthPMs = c4ByMonth.get(peakMonthKey) || [];
   281→  const peakMonthHours = peakMonthPMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
   282→  const peakWeekHours = peakMonthHours / 4; // Approximate 4 weeks per month
   283→  const overloadPercentage =
   284→    WEEKLY_MAN_HOUR_CAPACITY > 0
   285→      ? ((peakWeekHours - WEEKLY_MAN_HOUR_CAPACITY) / WEEKLY_MAN_HOUR_CAPACITY) * 100
   286→      : 0;
   287→
   288→  // Determine risk level
   289→  let riskLevel: BowWaveAnalysis['riskLevel'];
   290→  if (hasOverlapViolation || capitalRiskMillions >= 15) {
   291→    riskLevel = 'CRITICAL';
   292→  } else if (peakMonthPercentage >= 30 || capitalRiskMillions >= 10) {
   293→    riskLevel = 'HIGH';
   294→  } else if (peakMonthPercentage >= 20 || capitalRiskMillions >= 5) {
   295→    riskLevel = 'MEDIUM';
   296→  } else {
   297→    riskLevel = 'LOW';
   298→  }
   299→
   300→  return {
   301→    peakMonth: {
   302→      yearMonth: peakMonthKey || 'N/A',
   303→      c4Count: peakMonthCount,
   304→      percentage: Math.round(peakMonthPercentage * 10) / 10,
   305→    },
   306→    peakQuarter: {
   307→      quarter: peakQuarterKey || 'N/A',
   308→      c4Count: peakQuarterCount,
   309→      percentage: Math.round(peakQuarterPercentage * 10) / 10,
   310→    },
   311→    hasOverlapViolation,
   312→    affectedTrainCount: affectedTrainIds.size,
   313→    capitalRiskMillions: Math.round(capitalRiskMillions * 10) / 10,
   314→    capacityAnalysis: {
   315→      peakWeekHours: Math.round(peakWeekHours),
   316→      weeklyCapacity: WEEKLY_MAN_HOUR_CAPACITY,
   317→      overloadPercentage: Math.round(overloadPercentage),
   318→    },
   319→    riskLevel,
   320→  };
   321→}
   322→
   323→export interface AnalyzerConfig {
   324→  /** Analysis horizon in years (default: 3 for Q2 2027 from late 2026) */
   325→  horizonYears?: number;
   326→}
   327→
   328→/**
   329→ * Analyze bow-wave scenario from generated demo data
