/**
 * MMS Bow-Wave Scenario Analyzer
 *
 * Analyzes generated demo data to:
 * - Project future PM events based on current mileage and history
 * - Identify Q2 2027 maintenance clustering (bow-wave)
 * - Flag 40% C4 overlap violations
 * - Calculate capital risk concentration ($15M threshold)
 * - Generate visualization data (heatmap density, Gantt bars)
 *
 * @see specs/009-demo-application.md
 */

import { formatDate } from './generator';
import type {
  BowWaveAnalysis,
  BowWaveScenarioOutput,
  DemoPMHistory,
  DemoTrain,
  GanttBar,
  GeneratedData,
  MonthlyPMDensity,
  ProjectedPM,
} from './types';

/** Average C4 overhaul cost in millions */
const C4_COST_MILLIONS = 0.3;

/** Weekly man-hour capacity (40 hours x 5 technicians) */
const WEEKLY_MAN_HOUR_CAPACITY = 200;

/** Critical threshold: >15 PMs per month */
const CRITICAL_PM_THRESHOLD = 15;

/** Overlap violation threshold: 40% of fleet */
const OVERLAP_VIOLATION_THRESHOLD = 0.4;

/** Add days to a date */
function addDays(date: Date, days: number): Date {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
}

/** Get year-month string from date */
function getYearMonth(date: Date): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  return `${year}-${month}`;
}

/** Get quarter string from date (Q1-Q4 YYYY) */
function getQuarter(date: Date): string {
  const year = date.getFullYear();
  const quarter = Math.floor(date.getMonth() / 3) + 1;
  return `Q${quarter} ${year}`;
}

/** Calculate days between two dates */
function daysBetween(a: Date, b: Date): number {
  const msPerDay = 24 * 60 * 60 * 1000;
  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
}

interface PmTypeInfo {
  id: string;
  pmCode: string;
  intervalKm: number;
  intervalMonths: number;
  estimatedHours: number;
  displayColor: string;
}

/**
 * Project future PM events for a train based on current state and history
 */
function projectTrainPMs(
  train: DemoTrain,
  pmTypes: PmTypeInfo[],
  pmHistory: DemoPMHistory[],
  horizonDate: Date,
  today: Date
): ProjectedPM[] {
  const projections: ProjectedPM[] = [];

  // Get train's PM history
  const trainHistory = pmHistory.filter((pm) => pm.trainId === train.id);

  for (const pmType of pmTypes) {
    // Find the most recent completion of this PM type
    const lastCompletion = trainHistory
      .filter((pm) => pm.pmTypeId === pmType.id)
      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime())[0];

    // Calculate next due date using dual triggers (mileage and time)
    let nextDueDate: Date;
    let nextDueMileage: number;

    if (lastCompletion) {
      // Calculate from last completion
      const mileageSinceCompletion = train.currentMileageKm - lastCompletion.completedMileageKm;
      const kmToNextPm = pmType.intervalKm - mileageSinceCompletion;
      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));

      const daysSinceCompletion = daysBetween(lastCompletion.completionDate, today);
      const daysToTimeDue = Math.max(0, pmType.intervalMonths * 30 - daysSinceCompletion);

      // Dual trigger: whichever comes first
      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
      nextDueDate = addDays(today, daysToNextPm);
      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
    } else {
      // Cold start: assume PM was done at commissioning on-schedule
      const daysSinceCommissioning = daysBetween(train.commissioningDate, today);
      const cyclesFromCommissioning = Math.floor(train.currentMileageKm / pmType.intervalKm);
      const lastPmMileage = cyclesFromCommissioning * pmType.intervalKm;

      const kmToNextPm = pmType.intervalKm - (train.currentMileageKm - lastPmMileage);
      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));

      const monthsIntoCurrentCycle = (daysSinceCommissioning / 30) % pmType.intervalMonths;
      const daysToTimeDue = Math.max(0, (pmType.intervalMonths - monthsIntoCurrentCycle) * 30);

      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
      nextDueDate = addDays(today, daysToNextPm);
      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
    }

    // Project all PMs within horizon
    let currentDate = nextDueDate;
    let currentMileage = nextDueMileage;

    while (currentDate <= horizonDate) {
      projections.push({
        trainId: train.id,
        trainNumber: train.trainNumber,
        fleetCode: train.fleetCode,
        pmTypeId: pmType.id,
        pmCode: pmType.pmCode,
        projectedDate: new Date(currentDate),
        projectedMileage: Math.round(currentMileage),
        estimatedHours: pmType.estimatedHours,
        displayColor: pmType.displayColor,
      });

      // Calculate next interval
      const intervalDays = Math.round(pmType.intervalKm / train.estimatedDailyKm);
      const timeDays = pmType.intervalMonths * 30;
      const nextInterval = Math.min(intervalDays, timeDays);

      currentDate = addDays(currentDate, nextInterval);
      currentMileage += nextInterval * train.estimatedDailyKm;
    }
  }

  return projections;
}

/**
 * Calculate monthly PM density for heatmap visualization
 */
function calculateMonthlyDensity(projections: ProjectedPM[]): MonthlyPMDensity[] {
  const densityMap = new Map<string, MonthlyPMDensity>();

  for (const pm of projections) {
    const yearMonth = getYearMonth(pm.projectedDate);

    if (!densityMap.has(yearMonth)) {
      densityMap.set(yearMonth, {
        year: pm.projectedDate.getFullYear(),
        month: pm.projectedDate.getMonth() + 1,
        yearMonth,
        totalPMs: 0,
        pmsByType: {},
        isCritical: false,
        manHours: 0,
      });
    }

    const density = densityMap.get(yearMonth)!;
    density.totalPMs++;
    density.pmsByType[pm.pmCode] = (density.pmsByType[pm.pmCode] || 0) + 1;
    density.manHours += pm.estimatedHours;
  }

  // Mark critical months (>15 PMs)
  for (const density of densityMap.values()) {
    density.isCritical = density.totalPMs > CRITICAL_PM_THRESHOLD;
  }

  return Array.from(densityMap.values()).sort((a, b) => a.yearMonth.localeCompare(b.yearMonth));
}

/**
 * Generate Gantt bar data for tactical visualization
 */
function generateGanttBars(projections: ProjectedPM[]): GanttBar[] {
  return projections.map((pm) => {
    // Estimate duration in days based on hours (8 hour workday)
    const durationDays = Math.ceil(pm.estimatedHours / 8);
    const endDate = addDays(pm.projectedDate, durationDays);

    return {
      trainId: pm.trainId,
      trainNumber: pm.trainNumber,
      fleetCode: pm.fleetCode,
      pmCode: pm.pmCode,
      startDate: formatDate(pm.projectedDate),
      endDate: formatDate(endDate),
      estimatedHours: pm.estimatedHours,
      displayColor: pm.displayColor,
    };
  });
}

/**
 * Analyze bow-wave scenario from projected PMs
 */
function analyzeBowWave(projections: ProjectedPM[], fleetSize: number): BowWaveAnalysis {
  // Group C4 PMs by month and quarter
  const c4Projections = projections.filter((pm) => pm.pmCode === 'C4');

  const c4ByMonth = new Map<string, ProjectedPM[]>();
  const c4ByQuarter = new Map<string, ProjectedPM[]>();

  for (const pm of c4Projections) {
    const yearMonth = getYearMonth(pm.projectedDate);
    const quarter = getQuarter(pm.projectedDate);

    if (!c4ByMonth.has(yearMonth)) {
      c4ByMonth.set(yearMonth, []);
    }
    c4ByMonth.get(yearMonth)!.push(pm);

    if (!c4ByQuarter.has(quarter)) {
      c4ByQuarter.set(quarter, []);
    }
    c4ByQuarter.get(quarter)!.push(pm);
  }

  // Find peak month
  let peakMonthKey = '';
  let peakMonthCount = 0;
  for (const [month, pms] of c4ByMonth) {
    // Count unique trains
    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
    if (uniqueTrains > peakMonthCount) {
      peakMonthCount = uniqueTrains;
      peakMonthKey = month;
    }
  }

  // Find peak quarter
  let peakQuarterKey = '';
  let peakQuarterCount = 0;
  for (const [quarter, pms] of c4ByQuarter) {
    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
    if (uniqueTrains > peakQuarterCount) {
      peakQuarterCount = uniqueTrains;
      peakQuarterKey = quarter;
    }
  }

  // Calculate percentages
  const peakMonthPercentage = fleetSize > 0 ? (peakMonthCount / fleetSize) * 100 : 0;
  const peakQuarterPercentage = fleetSize > 0 ? (peakQuarterCount / fleetSize) * 100 : 0;

  // Check for 40% overlap violation
  const hasOverlapViolation = peakMonthPercentage >= OVERLAP_VIOLATION_THRESHOLD * 100;

  // Count affected trains (those with C4 in peak quarter)
  const affectedTrainIds = peakQuarterKey
    ? new Set(c4ByQuarter.get(peakQuarterKey)?.map((pm) => pm.trainId) || [])
    : new Set<string>();

  // Calculate capital risk (C4 count in peak quarter x cost per C4)
  const capitalRiskMillions = peakQuarterCount * C4_COST_MILLIONS;

  // Calculate man-hour capacity analysis for peak week
  const peakMonthPMs = c4ByMonth.get(peakMonthKey) || [];
  const peakMonthHours = peakMonthPMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
  const peakWeekHours = peakMonthHours / 4; // Approximate 4 weeks per month
  const overloadPercentage =
    WEEKLY_MAN_HOUR_CAPACITY > 0
      ? ((peakWeekHours - WEEKLY_MAN_HOUR_CAPACITY) / WEEKLY_MAN_HOUR_CAPACITY) * 100
      : 0;

  // Determine risk level
  let riskLevel: BowWaveAnalysis['riskLevel'];
  if (hasOverlapViolation || capitalRiskMillions >= 15) {
    riskLevel = 'CRITICAL';
  } else if (peakMonthPercentage >= 30 || capitalRiskMillions >= 10) {
    riskLevel = 'HIGH';
  } else if (peakMonthPercentage >= 20 || capitalRiskMillions >= 5) {
    riskLevel = 'MEDIUM';
  } else {
    riskLevel = 'LOW';
  }

  return {
    peakMonth: {
      yearMonth: peakMonthKey || 'N/A',
      c4Count: peakMonthCount,
      percentage: Math.round(peakMonthPercentage * 10) / 10,
    },
    peakQuarter: {
      quarter: peakQuarterKey || 'N/A',
      c4Count: peakQuarterCount,
      percentage: Math.round(peakQuarterPercentage * 10) / 10,
    },
    hasOverlapViolation,
    affectedTrainCount: affectedTrainIds.size,
    capitalRiskMillions: Math.round(capitalRiskMillions * 10) / 10,
    capacityAnalysis: {
      peakWeekHours: Math.round(peakWeekHours),
      weeklyCapacity: WEEKLY_MAN_HOUR_CAPACITY,
      overloadPercentage: Math.round(overloadPercentage),
    },
    riskLevel,
  };
}

export interface AnalyzerConfig {
  /** Analysis horizon in years (default: 3 for Q2 2027 from late 2026) */
  horizonYears?: number;
}

/**
 * Analyze bow-wave scenario from generated demo data
 *
 * This function:
 * 1. Projects future PM events based on current mileage and history
 * 2. Calculates monthly PM density for heatmap visualization
 * 3. Identifies peak C4 clustering (Q2 2027 scenario)
 * 4. Flags 40% overlap violations
 * 5. Calculates capital risk and capacity overload
 *
 * @param data - Generated demo data from generateDemoData()
 * @param config - Analyzer configuration
 * @returns Complete bow-wave scenario analysis output
 */
export function analyzeBowWaveScenario(
  data: GeneratedData,
  config: AnalyzerConfig = {}
): BowWaveScenarioOutput {
  const { horizonYears = 3 } = config;

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const horizonDate = new Date(today);
  horizonDate.setFullYear(horizonDate.getFullYear() + horizonYears);

  // Build PM type lookup by fleet
  const pmTypesByFleet = new Map<string, PmTypeInfo[]>();
  for (const pmType of data.pmTypes) {
    const fleet = data.fleets.find((f) => f.id === pmType.fleetId);
    if (fleet) {
      if (!pmTypesByFleet.has(fleet.code)) {
        pmTypesByFleet.set(fleet.code, []);
      }
      pmTypesByFleet.get(fleet.code)!.push({
        id: pmType.id,
        pmCode: pmType.pmCode,
        intervalKm: pmType.intervalKm,
        intervalMonths: pmType.intervalMonths,
        estimatedHours: pmType.estimatedHours,
        displayColor: pmType.displayColor,
      });
    }
  }

  // Project PMs for all trains
  const allProjections: ProjectedPM[] = [];
  for (const train of data.trains) {
    const pmTypes = pmTypesByFleet.get(train.fleetCode) || [];
    const trainProjections = projectTrainPMs(train, pmTypes, data.pmHistory, horizonDate, today);
    allProjections.push(...trainProjections);
  }

  // Sort projections by date
  allProjections.sort((a, b) => a.projectedDate.getTime() - b.projectedDate.getTime());

  // Calculate monthly density
  const monthlyDensity = calculateMonthlyDensity(allProjections);

  // Generate Gantt bars
  const ganttBars = generateGanttBars(allProjections);

  // Analyze bow-wave
  const analysis = analyzeBowWave(allProjections, data.trains.length);

  return {
    projectedPMs: allProjections,
    monthlyDensity,
    analysis,
    ganttBars,
    horizonYears,
    fleetSize: data.trains.length,
  };
}

/**
 * Format bow-wave analysis as human-readable report
 */
export function formatAnalysisReport(output: BowWaveScenarioOutput): string {
  const lines: string[] = [];

  lines.push('═══════════════════════════════════════════════════════════════════');
  lines.push('                    MMS BOW-WAVE SCENARIO ANALYSIS');
  lines.push('═══════════════════════════════════════════════════════════════════');
  lines.push('');
  lines.push(`Fleet Size: ${output.fleetSize} trains`);
  lines.push(`Analysis Horizon: ${output.horizonYears} years`);
  lines.push(`Total Projected PMs: ${output.projectedPMs.length}`);
  lines.push('');

  lines.push('─── RISK SUMMARY ───');
  lines.push(`Risk Level: ${output.analysis.riskLevel}`);
  lines.push(`40% Overlap Violation: ${output.analysis.hasOverlapViolation ? 'YES - CRITICAL' : 'No'}`);
  lines.push(`Capital Risk: $${output.analysis.capitalRiskMillions}M`);
  lines.push(`Affected Trains: ${output.analysis.affectedTrainCount}`);
  lines.push('');

  lines.push('─── PEAK C4 CONCENTRATION ───');
  lines.push(`Peak Month: ${output.analysis.peakMonth.yearMonth}`);
  lines.push(`  - C4 Count: ${output.analysis.peakMonth.c4Count}`);
  lines.push(`  - Fleet %: ${output.analysis.peakMonth.percentage}%`);
  lines.push('');
  lines.push(`Peak Quarter: ${output.analysis.peakQuarter.quarter}`);
  lines.push(`  - C4 Count: ${output.analysis.peakQuarter.c4Count}`);
  lines.push(`  - Fleet %: ${output.analysis.peakQuarter.percentage}%`);
  lines.push('');

  lines.push('─── CAPACITY ANALYSIS ───');
  lines.push(`Peak Week Hours: ${output.analysis.capacityAnalysis.peakWeekHours}`);
  lines.push(`Weekly Capacity: ${output.analysis.capacityAnalysis.weeklyCapacity}`);
  lines.push(
    `Overload: ${output.analysis.capacityAnalysis.overloadPercentage > 0 ? '+' : ''}${output.analysis.capacityAnalysis.overloadPercentage}%`
  );
  lines.push('');

  lines.push('─── MONTHLY DENSITY (Critical Months) ───');
  const criticalMonths = output.monthlyDensity.filter((m) => m.isCritical);
  if (criticalMonths.length === 0) {
    lines.push('No critical months (>15 PMs/month) detected.');
  } else {
    for (const month of criticalMonths) {
      lines.push(`${month.yearMonth}: ${month.totalPMs} PMs, ${month.manHours} man-hours`);
      const pmTypes = Object.entries(month.pmsByType)
        .map(([code, count]) => `${code}:${count}`)
        .join(', ');
      lines.push(`  Types: ${pmTypes}`);
    }
  }
  lines.push('');

  lines.push('═══════════════════════════════════════════════════════════════════');

  return lines.join('\n');
}

/**
 * MMS Demo Data Generator Module
 *
 * @example
 * ```typescript
 * import { generateDemoData, generateSQL, analyzeBowWaveScenario } from './demo';
 *
 * // Generate data with default settings (128 trains, 5 years history)
 * const data = generateDemoData();
 *
 * // Generate SQL for database seeding
 * const sql = generateSQL(data);
 *
 * // Generate with bow-wave scenario enabled
 * const bowWaveData = generateDemoData({ enableBowWave: true });
 *
 * // Analyze bow-wave scenario
 * const analysis = analyzeBowWaveScenario(bowWaveData);
 * console.log(analysis.analysis.riskLevel);
 * ```
 */

export { generateDemoData, generateSQL, formatDate } from './generator';
export { analyzeBowWaveScenario, formatAnalysisReport } from './analyzer';
export type {
  DemoFleet,
  DemoPMRule,
  DemoTrain,
  DemoPMHistory,
  DemoMileageReading,
  DemoServiceDemand,
  GeneratorConfig,
  GeneratedData,
  ProjectedPM,
  MonthlyPMDensity,
  BowWaveAnalysis,
  GanttBar,
  BowWaveScenarioOutput,
} from './types';
export {
  DEMO_DEPOTS,
  DEMO_FLEETS,
  PM_RULES_BY_FLEET,
  SERVICE_DEMAND_PROFILES,
  TRACK_CONFIGS,
} from './data';

